// Build the structured masterTest.json database programmatically
const finalData = {};
const completions = generateSentenceCompletions();
const blanks = generateFillBlanks();
const jumbled = generateJumbledWords();
const passages = generatePassageReconstructions();

for (let i = 1; i <= 20; i++) {
    const testKey = i.toString();
    finalData[testKey] = {
        typing: [
            {
                id: 1,
                paragraph: typingParagraphs[i - 1]
            }
        ],
        sentenceCompletion: completions.slice((i - 1) * 10, i * 10).map((item, idx) => ({ ...item, id: idx + 1 })),
        fillBlanks: blanks.slice((i - 1) * 10, i * 10).map((item, idx) => ({ ...item, id: idx + 1 })),
        jumbledWords: jumbled.slice((i - 1) * 15, i * 15).map((item, idx) => ({ ...item, id: idx + 1 })),
        passageReconstruction: passages.slice((i - 1) * 3, i * 3).map((item, idx) => ({ ...item, id: idx + 1 })),
        emailWriting: [
            {
                id: 1,
                prompt: emailPrompts[i - 1]
            }
        ]
    };
}

