console.log("Total Mock Tests Generated:", Object.keys(finalData).length);
let totalSC = 0;
let totalFB = 0;
let totalJW = 0;
let totalPR = 0;

for (let i = 1; i <= 20; i++) {
    const data = finalData[i.toString()];
    totalSC += data.sentenceCompletion.length;
    totalFB += data.fillBlanks.length;
    totalJW += data.jumbledWords.length;
    totalPR += data.passageReconstruction.length;
}

console.log("Total Typing Paragraphs (Target 20):", typingParagraphs.length);
console.log("Total Sentence Completions (Target 200):", totalSC);
console.log("Total Fill Blanks (Target 200):", totalFB);
console.log("Total Jumbled Words (Target 300):", totalJW);
console.log("Total Passages Reconstructed (Target 60):", totalPR);
console.log("Total Emails (Target 20):", emailPrompts.length);
console.log("=========================================");

// Write to final file
const targetFilePath = path.join(__dirname, '../src/data/masterTest.json');
fs.writeFileSync(targetFilePath, JSON.stringify(finalData, null, 2), 'utf-8');
console.log("Database file successfully written to:", targetFilePath);
